  unsigned char h3_priority_urgency;
  unsigned char h3_priority_incremental;
#endif
```

### 6. src/tool_operate.c
**Add priority handling before the curl_easy_perform call (around line 1655):**

```c
#ifdef USE_HTTP3
      if(config->h3_priority_urgency || config->h3_priority_incremental) {
        struct curl_h3_stream_priority priority;
        priority.urgency = config->h3_priority_urgency;
        priority.incremental = config->h3_priority_incremental;
        my_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);
      }
#endif
```

### 7. lib/vquic/curl_ngtcp2.c
**Add priority header formation in the request setup (in h3_stream_ctx structure and when sending HEADERS):**

```c
/* In h3_stream_ctx or stream creation function, add: */
static void h3_priority_to_header(struct Curl_easy *data, struct dynbuf *buf)
{
  /* Format Priority header per RFC 9218 */
  Curl_dyn_reset(buf);

  /* Get priority from data->set */
  unsigned char urgency = 3;  /* default */
  unsigned char incremental = 0;  /* default */

#ifdef USE_HTTP3
  if(data->set.h3_priority_urgency)
    urgency = data->set.h3_priority_urgency;
  if(data->set.h3_priority_incremental)
    incremental = data->set.h3_priority_incremental;
#endif

  /* Build Priority header: u=<0-7>[, i] */
  if(Curl_dyn_addf(buf, \"u=%u\", urgency) < 0)
    return CURLE_OUT_OF_MEMORY;

  if(incremental) {
    if(Curl_dyn_add(buf, \", i\") < 0)
      return CURLE_OUT_OF_MEMORY;
  }

  /* Add Priority header to request */
  /* This would be integrated with the existing header handling */
}

/* When creating HTTP request, include the Priority header:
   Priority: u=<0-7>[, i]

   Example implementations:
   - nghttp3_nv_array with Priority field
   - Or use PRIORITY_UPDATE frame after stream creation
*/
```

