#include "curlcheck.h"

#ifdef USE_HTTP3

#include <curl/curl.h>

static CURLcode unit_setup(void)
{
  return CURLE_OK;
}

static void unit_teardown(void)
{
}

UNITTEST_START

{
  /* Test CURLOPT_H3_STREAM_PRIORITY option */
  CURL *curl = curl_easy_init();
  CURLcode result;
  struct curl_h3_stream_priority priority;

  if(!curl) {
    return CURLE_OUT_OF_MEMORY;
  }

  /* Test setting priority with urgency 0 */
  priority.urgency = 0;
  priority.incremental = 0;
  result = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);
  fail_unless(result == CURLE_OK, "Failed to set H3 priority");

  /* Test setting priority with urgency 7 */
  priority.urgency = 7;
  priority.incremental = 1;
  result = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);
  fail_unless(result == CURLE_OK, "Failed to set H3 priority with incremental");

  /* Test invalid urgency (> 7) should fail or be clamped */
  priority.urgency = 8;
  priority.incremental = 0;
  result = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);
  fail_unless(result == CURLE_BAD_FUNCTION_ARGUMENT, "Should reject urgency > 7");

  /* Test reset to NULL */
  result = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, NULL);
  fail_unless(result == CURLE_OK, "Failed to reset H3 priority");

  curl_easy_cleanup(curl);
}

UNITTEST_STOP

#endif
```

## Implementation Strategy

### Priority Header Format (RFC 9218)
- **Urgency parameter (u)**: Integer 0-7
  - 0 = highest priority
  - 3 = default (neutral)
  - 7 = lowest (background/bulk)

- **Incremental parameter (i)**: Boolean
  - Indicates response can be processed incrementally
  - Default: false (not present)

### Header Format Examples
```
Priority: u=0                  /* Highest priority, not incremental */
Priority: u=3, i               /* Default urgency, incremental */
Priority: u=7                  /* Lowest priority, not incremental */
```

