# Implementation Patches for RFC 9218 HTTP/3 Extensible Priorities

## 1. include/curl/curl.h Changes

### Add struct definition after enum CURLUcode (around line 2250+):
```c
/* HTTP/3 Stream Priority (RFC 9218) */
struct curl_h3_stream_priority {
  unsigned char urgency;      /* 0-7, where 0 is highest priority */
  unsigned char incremental;  /* 0 or 1 - can be processed incrementally */
};
```

### Add option enum before CURLOPT_LASTENTRY (around line 2213):
Replace:
```c
  /* set a specific client IP for HAProxy PROXY protocol header? */
  CURLOPT(CURLOPT_HAPROXY_CLIENT_IP, CURLOPTTYPE_STRINGPOINT, 323),

  CURLOPT_LASTENTRY /* the last unused */
} CURLoption;
```

With:
```c
  /* set a specific client IP for HAProxy PROXY protocol header? */
  CURLOPT(CURLOPT_HAPROXY_CLIENT_IP, CURLOPTTYPE_STRINGPOINT, 323),

  /* Set HTTP/3 stream priority (RFC 9218) with urgency and incremental flag */
  CURLOPT(CURLOPT_H3_STREAM_PRIORITY, CURLOPTTYPE_OBJECTPOINT, 324),

  CURLOPT_LASTENTRY /* the last unused */
} CURLoption;
```

---

## 2. lib/urldata.h Changes

### Modify struct Curl_data_priority (around line 1244):
Replace:
```c
/**
 * Priority information for an easy handle in relation to others
 * on the same connection.
 * TODO: we need to adapt it to the new priority scheme as defined in RFC 9218
 */
struct Curl_data_priority {
#ifdef USE_NGHTTP2
  /* tree like dependencies only implemented in nghttp2 */
  struct Curl_easy *parent;
  struct Curl_data_prio_node *children;
#endif
  int weight;
#ifdef USE_NGHTTP2
  BIT(exclusive);
#endif
};
```

With:
```c
/**
 * Priority information for an easy handle in relation to others
 * on the same connection.
 * Updated to support RFC 9218 (HTTP/3) in addition to HTTP/2 priorities
 */
struct Curl_data_priority {
#ifdef USE_NGHTTP2
  /* tree like dependencies only implemented in nghttp2 (HTTP/2) */
  struct Curl_easy *parent;
  struct Curl_data_prio_node *children;
#endif
  int weight;
#ifdef USE_NGHTTP2
  BIT(exclusive);
#endif
#ifdef USE_HTTP3
  /* RFC 9218 HTTP/3 Extensible Priorities */
  unsigned char h3_urgency;      /* 0-7, 0=highest, 3=default */
  unsigned char h3_incremental;  /* boolean flag */
#endif
};
```

### Add fields to struct UserDefined (after line 1813):
Replace:
```c
  long expect_100_timeout; /* in milliseconds */
#if defined(USE_HTTP2) || defined(USE_HTTP3)
  struct Curl_data_priority priority;
#endif
  curl_resolver_start_callback resolver_start; /* optional callback called
```

With:
```c
  long expect_100_timeout; /* in milliseconds */
#if defined(USE_HTTP2) || defined(USE_HTTP3)
  struct Curl_data_priority priority;
#endif
#ifdef USE_HTTP3
  /* RFC 9218 HTTP/3 stream priority */
  unsigned char h3_priority_urgency;      /* 0-7 for HTTP/3 */
  unsigned char h3_priority_incremental;  /* boolean for HTTP/3 */
#endif
  curl_resolver_start_callback resolver_start; /* optional callback called
```

---

## 3. lib/setopt.c Changes

### Add case before default (around line 3170):
Replace:
```c
  case CURLOPT_QUICK_EXIT:
    data->set.quick_exit = (0 != va_arg(param, long)) ? 1L:0L;
    break;
  default:
    /* unknown tag and its companion, just ignore: */
    result = CURLE_UNKNOWN_OPTION;
    break;
  }

  return result;
}
```

With:
```c
  case CURLOPT_QUICK_EXIT:
    data->set.quick_exit = (0 != va_arg(param, long)) ? 1L:0L;
    break;

#ifdef USE_HTTP3
  case CURLOPT_H3_STREAM_PRIORITY:
    /*
     * Set HTTP/3 stream priority (RFC 9218) with urgency and incremental flag
     */
  {
    struct curl_h3_stream_priority *priority = va_arg(param, struct curl_h3_stream_priority *);

    if(!priority) {
      /* Reset to defaults */
      data->set.h3_priority_urgency = 3;      /* default urgency */
      data->set.h3_priority_incremental = 0;  /* default: non-incremental */
    } else {
      /* Validate urgency (0-7) */
      if(priority->urgency > 7)
        return CURLE_BAD_FUNCTION_ARGUMENT;

      data->set.h3_priority_urgency = priority->urgency;
      data->set.h3_priority_incremental = priority->incremental ? 1 : 0;
    }
    break;
  }
#endif

  default:
    /* unknown tag and its companion, just ignore: */
    result = CURLE_UNKNOWN_OPTION;
    break;
  }

  return result;
}
```

---

## 4. src/tool_cfgable.h Changes

### Add fields to struct OperationConfig:
Near the end of the struct, before the closing brace, add:
```c
#ifdef USE_HTTP3
  /* RFC 9218 HTTP/3 stream priority */
  unsigned char h3_priority_urgency;
  unsigned char h3_priority_incremental;
#endif
```

---

## 5. src/tool_getparam.c Changes

### Add option alias to aliases array (around line 100):
Add after other HTTP3-related options:
```c
  {\"*@H3\", \"h3-priority\",              ARG_STRING},
```

### Add parsing logic in the parameter loop:
In the main parameter parsing section where other options are handled, add:

```c
#ifdef USE_HTTP3
      else if(strncasecompare(\"h3-priority\", 12, &p->name[i], arg_len)) {
        const char *priority_str = nextarg;
        if(!priority_str)
          return PARAM_MISSING_VALUE;

        /* Parse format: u=N[,i]
           Example: \"u=3\" or \"u=0,i\" */
        unsigned char urgency = 3;  /* default */
        unsigned char incremental = 0;  /* default */

        /* Parse urgency parameter */
        if(strncmp(priority_str, \"u=\", 2) == 0) {
          char *end;
          long val = strtol(priority_str + 2, &end, 10);
          if(val < 0 || val > 7) {
            warnf(global, \"Invalid urgency value (must be 0-7): %ld\\n\", val);
            return PARAM_BAD_USE;
          }
          urgency = (unsigned char)val;

          /* Check for incremental flag */
          if(*end == ',' && *(end+1) == 'i') {
            incremental = 1;
          }
        } else {
          warnf(global, \"Invalid priority format. Use: u=<0-7>[,i]\\n\");
          return PARAM_BAD_USE;
        }

        config->h3_priority_urgency = urgency;
        config->h3_priority_incremental = incremental;
      }
#endif
```

---

## 6. src/tool_operate.c Changes

### Add priority handling before curl_easy_perform (around line 1650):
Before the `my_setopt_bitmask(curl, CURLOPT_HTTPAUTH...` line, add:

```c
#ifdef USE_HTTP3
      if(config->h3_priority_urgency || config->h3_priority_incremental) {
        struct curl_h3_stream_priority priority;
        priority.urgency = config->h3_priority_urgency;
        priority.incremental = config->h3_priority_incremental;
        my_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, &priority);
      }
#endif
```

---

## 7. lib/vquic/curl_ngtcp2.c Changes

### Add Priority header formation:
In the HTTP/3 request header setup section (where nghttp3_nv arrays are created):

```c
/* Function to add Priority header for RFC 9218 */
static CURLcode h3_add_priority_header(
    struct Curl_easy *data,
    struct nghttp3_nv **nva,
    int *nva_count)
{
#ifdef USE_HTTP3
  if(data->set.h3_priority_urgency || data->set.h3_priority_incremental) {
    struct dynbuf buf;
    Curl_dyn_init(&buf, CURL_MAX_HTTP_HEADER);

    /* Format: u=<0-7>[, i] */
    if(Curl_dyn_addf(&buf, \"u=%u\", data->set.h3_priority_urgency) < 0)
      return CURLE_OUT_OF_MEMORY;

    if(data->set.h3_priority_incremental) {
      if(Curl_dyn_add(&buf, \", i\") < 0)
        return CURLE_OUT_OF_MEMORY;
    }

    /* Add to header array */
    nghttp3_nv *nv = &(*nva)[*nva_count];
    nv->name = (unsigned char *)\"priority\";
    nv->namelen = 8;
    nv->value = (unsigned char *)Curl_dyn_ptr(&buf);
    nv->valuelen = Curl_dyn_len(&buf);
    nv->flags = NGHTTP3_NV_FLAG_NONE;
    (*nva_count)++;
  }
#endif
  return CURLE_OK;
}
```

Then call this function when creating request headers:
```c
/* In the request header creation function */
h3_add_priority_header(data, &nva, &nva_count);
```

---

## 8. lib/easyoptions.c Updates (if needed)

Add entry to the easyoptions mapping (around line 180):
```c
  {\"H3_STREAM_PRIORITY\", CURLOPT_H3_STREAM_PRIORITY, CURLOT_OBJECT, 0},
```

Note: The exact type (CURLOT_OBJECT vs other) may need adjustment based on existing patterns.

---

## Compilation Flags

All HTTP/3 specific code should be wrapped with:
```c
#ifdef USE_HTTP3
  /* code here */
#endif
```

This ensures the code is only compiled when HTTP/3 support is enabled.

---

## Testing

Run the unit test:
```bash
cd tests/unit
make unit_h3_priority
./unit_h3_priority
```

Test CLI:
```bash
curl --h3-priority u=0 https://example.com
curl --h3-priority u=3,i https://example.com
curl --h3-priority u=7 https://example.com
```

