/*
 * Modifications to lib/vquic/curl_ngtcp2.c for RFC 9218 HTTP/3 priority support
 *
 * These modifications add support for sending HTTP/3 stream priorities
 * using the Priority header as defined in RFC 9218.
 */

/*
 * 1. Add helper function to create Priority header value.
 *    Place this near other header-related helper functions:
 */

#ifdef USE_HTTP3
static CURLcode h3_priority_header_value(struct Curl_easy *data, struct dynbuf *buf)
{
  /* Format RFC 9218 Priority header: u=<0-7>[, i] */
  unsigned char urgency = 3;      /* default urgency */
  unsigned char incremental = 0;  /* default non-incremental */

  Curl_dyn_reset(buf);

  /* Get priority settings from easy handle */
  if(data->set.h3_priority_urgency)
    urgency = data->set.h3_priority_urgency;
  if(data->set.h3_priority_incremental)
    incremental = data->set.h3_priority_incremental;

  /* Build header value: u=<0-7>[, i] */
  if(Curl_dyn_addf(buf, \"u=%u\", urgency) < 0)
    return CURLE_OUT_OF_MEMORY;

  if(incremental) {
    if(Curl_dyn_add(buf, \", i\") < 0)
      return CURLE_OUT_OF_MEMORY;
  }

  return CURLE_OK;
}
#endif

/*
 * 2. Integrate Priority header into request headers.
 *    In the function that creates HTTP/3 request headers (likely in h3_stream_ctx setup),
 *    add the Priority header to the nghttp3_nv array before sending.
 *
 *    Example integration (in the header array building code):
 */

#ifdef USE_HTTP3
  /* Add Priority header for RFC 9218 HTTP/3 stream priority */
  if(data->set.h3_priority_urgency || data->set.h3_priority_incremental) {
    struct dynbuf priority_buf;
    Curl_dyn_init(&priority_buf, 32);  /* Small buffer for priority header */

    if(h3_priority_header_value(data, &priority_buf) == CURLE_OK) {
      /* Create nv entry for Priority header */
      nghttp3_nv priority_nv;
      priority_nv.name = (unsigned char *)\"priority\";
      priority_nv.namelen = 8;
      priority_nv.value = (unsigned char *)Curl_dyn_ptr(&priority_buf);
      priority_nv.valuelen = Curl_dyn_len(&priority_buf);
      priority_nv.flags = NGHTTP3_NV_FLAG_NONE;

      /* Add to header array */
      /* (This depends on the exact structure of how headers are added) */

      Curl_dyn_free(&priority_buf);
    }
  }
#endif

/*
 * 3. Alternative: Use nghttp3's priority update mechanism if available
 *    Some implementations may prefer sending PRIORITY_UPDATE frame instead of header.
 *    This would use nghttp3_conn_prioritize_stream() if available.
 */

#ifdef USE_HTTP3
/* Optional: Use PRIORITY_UPDATE frame approach
