    struct cf_ngtcp2_ctx *ctx,
    int64_t stream_id,
    struct Curl_easy *data)
{
  unsigned char urgency = data->set.h3_priority_urgency;
  unsigned char incremental = data->set.h3_priority_incremental;

  /* If nghttp3 supports priority updates */
